// 【V46.0 快取層】提取查詢參數並生成快取鍵
const query = $input.item.json.query || {};
const queryStr = JSON.stringify({
  year: query.year || '',
  month: query.month || '',
  status: query.status || '',
  batch: query.batch || '',
  search: query.search || ''
});

// 生成簡單雜湊作為快取鍵
let hash = 0;
for (let i = 0; i < queryStr.length; i++) {
    const char = queryStr.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
}
const cacheKey = `fhs_review_${Math.abs(hash)}`;
const cacheFile = `/tmp/${cacheKey}.json`;

let formulas = [];
if (query.year && query.month) {
    formulas.push(`DATETIME_FORMAT(CREATED_TIME(), 'YYYY-MM') = '${query.year}-${query.month}'`);
} else if (query.year) {
    formulas.push(`DATETIME_FORMAT(CREATED_TIME(), 'YYYY') = '${query.year}'`);
} else if (query.month) {
    formulas.push(`DATETIME_FORMAT(CREATED_TIME(), 'MM') = '${query.month}'`);
}

if (query.status) {
    formulas.push(`{Process_Status} = '${query.status}'`);
}
if (query.batch) {
    formulas.push(`FIND('${query.batch}', {Batch_Number}) > 0`);
}
if (query.search) {
    formulas.push(`OR(FIND('${query.search}', {Customer_Name}) > 0, FIND('${query.search}', {Order_ID}) > 0)`);
}

let finalFormula = "";
if (formulas.length > 0) {
    finalFormula = `AND(${formulas.join(', ')})`;
}

return { json: { formula: finalFormula, cacheKey, cacheFile, queryParams: query } };

// 【V46.0 快取驗證】檢查快取有效性 (TTL: 5分鐘)
const buildFormulaOutput = $("Build Formula & Cache Key").first();
const cacheReadOutput = $("Try Read Cache").first();

let isCacheValid = false;
let cachedData = null;

if (cacheReadOutput && cacheReadOutput.binary && cacheReadOutput.binary.data) {
    try {
        const cacheContent = Buffer.from(cacheReadOutput.binary.data.data, 'base64').toString();
        const cacheObj = JSON.parse(cacheContent);
        const now = Date.now();
        const ageMs = now - cacheObj.timestamp;
        const ttlMs = 5 * 60 * 1000; // 5分鐘

        if (ageMs < ttlMs) {
            isCacheValid = true;
            cachedData = cacheObj.data;
        }
    } catch (e) {
        // 快取讀取或解析失敗，視為無效
    }
}

return { 
  json: { 
    isCacheValid,
    cachedData,
    formula: buildFormulaOutput.json.formula,
    cacheKey: buildFormulaOutput.json.cacheKey,
    cacheFile: buildFormulaOutput.json.cacheFile,
    queryParams: buildFormulaOutput.json.queryParams
  }
};

// 【快取命中】直接返回快取數據
const validatorOutput = $("Check Cache Validity").first();
return { 
  json: { 
    success: true, 
    count: validatorOutput.json.cachedData ? validatorOutput.json.cachedData.orders.length : 0,
    orders: validatorOutput.json.cachedData ? validatorOutput.json.cachedData.orders : [],
    _cacheHit: true
  }
};

const items = $input.all();
if (items.length === 0 || !items[0].json.id) return { json: { success: true, count: 0, mainOrders: [] } };

const mainOrders = items.map(item => {
    const data = item.json;
    return {
        id: data.id,
        Order_ID: data.Order_ID || 'N/A',
        Date: data.createdTime,
        Customer: data.Customer_Name || '-',
        Batch: data.Batch_Number || '',
        Status: data.Process_Status || '0 什麼都未做',
        Admin_Notes: data.Admin_Notes || '',
        Sales: data.Final_Sale_Price || 0,
        Cost: data.Total_Cost || 0,
        Net_Profit: data.Net_Profit || 0,
        Raw_Form_State: data.Raw_Form_State || '',
        Order_Items_Links: data.Order_Items || []
    };
});
return { json: { mainOrders } };

const mainOrders = $input.item.json.mainOrders || [];
let allSubItemIds = [];
mainOrders.forEach(mo => {
    if (mo.Order_Items_Links && mo.Order_Items_Links.length > 0) {
        allSubItemIds = allSubItemIds.concat(mo.Order_Items_Links);
    }
});

if (allSubItemIds.length === 0) {
    return { json: { formula: "RECORD_ID()='INVALID'", mainOrders } };
}

const uniqueIds = [...new Set(allSubItemIds)];
const formulaParts = uniqueIds.map(id => `RECORD_ID()='${id}'`);
let chunks = [];
for (let i = 0; i < formulaParts.length; i+=50) {
   chunks.push(`OR(${formulaParts.slice(i, i+50).join(',')})`);
}
let finalFormula = chunks.length > 1 ? `OR(${chunks.join(',')})` : chunks[0];
return { json: { formula: finalFormula, mainOrders } };

// 【快取寫入】在返回前保存到快取文件
const validatorOutput = $("Check Cache Validity").first();
const cacheFile = validatorOutput.json.cacheFile;

const subItemsData = $("Search Order_Items").all();
const buildFormulaNode = $("Build SubItems Formula").first();
const mainOrdersContext = (buildFormulaNode && buildFormulaNode.json) ? buildFormulaNode.json.mainOrders : [];

let productsCache = [];

const productMap = {};
productsCache.forEach(p => { productMap[p.id] = p.fields; });

const subItemsMap = {};
if (subItemsData.length > 0 && subItemsData[0].json.id) {
    subItemsData.forEach(item => {
        const data = item.json;
        const pid = data.Product_Link && data.Product_Link.length > 0 ? data.Product_Link[0] : '';
        const cachedProduct = productMap[pid] || {};

        subItemsMap[data.id] = {
            id: data.id,
            Item_ID: data.Item_ID,
            Product: cachedProduct.Product_Name || pid,
            Category: cachedProduct.Main_Category || (data.Item_Category && data.Item_Category.length > 0 ? data.Item_Category[0] : ''),
            Qty: data.Quantity || 0,
            BaseCost: cachedProduct.Total_Base_Cost || (data.Item_BaseCost && data.Item_BaseCost.length > 0 ? data.Item_BaseCost[0] : 0),
            Engraving: data.Engraving_Text || '',
            Specification: data.Specification || '',
            OrderKey: data.Order_Item_Key || '',
            Batch: data.Batch_Number || '',
            Status: data.Process_Status || ''
        };
    });
}

if (Array.isArray(mainOrdersContext)) {
    mainOrdersContext.forEach(mo => {
        mo.items = [];
        if (mo.Order_Items_Links && Array.isArray(mo.Order_Items_Links)) {
            mo.Order_Items_Links.forEach(linkId => {
                if (subItemsMap[linkId]) {
                    mo.items.push(subItemsMap[linkId]);
                }
            });
        }
    });
}

const responseData = { 
  success: true, 
  count: mainOrdersContext ? mainOrdersContext.length : 0, 
  orders: mainOrdersContext,
  _cacheFresh: true
};

// 準備快取數據 (JSON 序列化後轉 Base64)
const cacheObj = {
  timestamp: Date.now(),
  data: responseData
};
const jsonStr = JSON.stringify(cacheObj);
const buffer = Buffer.from(jsonStr, 'utf8');
const base64 = buffer.toString('base64');

return { 
  json: responseData,
  binary: {
    data: {
      data: base64,
      mimeType: 'application/octet-stream',
      fileName: cacheFile
    }
  }
};
